class Solution:
    def minReverseOperations(self, n, p, banned, k):
        from collections import deque
        banned_set = set(banned)
        dist = [-1] * n
        dist[p] = 0
        visited = {p}
        q = deque([p])
        while q:
            i = q.popleft()
            for l in range(0, n - k + 1):
                r = l + k - 1
                if not (l <= i <= r):
                    continue
                j = l + r - i
                if j in visited or j in banned_set:
                    continue
                visited.add(j)
                dist[j] = dist[i] + 1
                q.append(j)
        return dist

