var minReverseOperations = function(n, p, banned, k) {
    const bannedSet = new Set(banned);
    const dist = new Array(n).fill(-1);
    dist[p] = 0;
    const unvisited = [new Set(), new Set()];
    for (let x = 0; x < n; x++) {
        if (x !== p && !bannedSet.has(x)) unvisited[x % 2].add(x);
    }
    let frontier = [p];
    let d = 0;
    while (frontier.length > 0) {
        const nextFrontier = [];
        for (const i of frontier) {
            const lo = 2 * Math.max(0, i - k + 1) + k - 1 - i;
            const hi = 2 * Math.min(i, n - k) + k - 1 - i;
            if (lo > hi) continue;
            const bucket = unvisited[((lo % 2) + 2) % 2];
            const reached = [];
            for (const x of bucket) {
                if (x >= lo && x <= hi) reached.push(x);
            }
            for (const x of reached) {
                bucket.delete(x);
                dist[x] = d + 1;
                nextFrontier.push(x);
            }
        }
        frontier = nextFrontier;
        d++;
    }
    return dist;
};
